	t.Run("challenge storage uses correct device IDs", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		authServer := as.AuthServer.(*auth.Server)
		mfaChallenge, err := authServer.GetMFAAuthenticateChallengeForTesting(ctx, username, u2fAuthStorage)
