package main

import (
	"context"
	"encoding/base64"
	"testing"
	"time"

	"github.com/jonboulle/clockwork"
	"github.com/stretchr/testify/require"

	"github.com/gravitational/teleport"
	"github.com/gravitational/teleport/api/client/proto"
	"github.com/gravitational/teleport/api/types"
	"github.com/gravitational/teleport/lib/auth"
	"github.com/gravitational/teleport/lib/auth/mocku2f"
	"github.com/gravitational/teleport/lib/auth/u2f"
	"github.com/gravitational/teleport/lib/services"
)

// TestRegression verifies that multiple registered U2F devices all receive
// authentication challenges during login, rather than being limited to a
// single device.
//
// This is a regression test for the issue where users with multiple U2F
// hardware tokens would only see one device presented during login, even
// though they had registered multiple devices.
func TestRegression(t *testing.T) {
	ctx := context.Background()
	clock := clockwork.NewFakeClock()

	// Create an auth server for testing
	as, err := auth.NewTestAuthServer(auth.TestAuthServerConfig{
		Dir:   t.TempDir(),
		Clock: clock,
	})
	require.NoError(t, err, "failed to create test auth server")

	// Enable U2F support
	authPref, err := services.NewAuthPreference(types.AuthPreferenceSpecV2{
		Type: teleport.Local,
		U2F: &types.U2F{
			AppID:  "teleport",
			Facets: []string{"teleport"},
		},
	})
	require.NoError(t, err, "failed to create auth preference")
	err = as.AuthServer.SetAuthPreference(authPref)
	require.NoError(t, err, "failed to set auth preference")

	// Create a test user
	user, _, err := auth.CreateUserAndRole(as.AuthServer, "u2f-user", []string{"role"})
	require.NoError(t, err, "failed to create user")

	username := user.GetName()
	u2fConfig, err := authPref.GetU2F()
	require.NoError(t, err, "failed to get U2F config")

	// Register the first U2F device
	firstDeviceName := "u2f-key-1"
	firstMockDevice, err := mocku2f.Create()
	require.NoError(t, err, "failed to create first mock U2F device")

	// Initiate registration for the first device
	u2fStorage, err := u2f.InMemoryRegistrationStorage(as.AuthServer.Identity)
	require.NoError(t, err, "failed to create U2F registration storage")

	firstChallenge, err := u2f.RegisterInit(ctx, u2f.RegisterInitParams{
		StorageKey: username,
		AppConfig:  *u2fConfig,
		Storage:    u2fStorage,
	})
	require.NoError(t, err, "failed to initiate first device registration")

	firstRegResp, err := firstMockDevice.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: firstChallenge.Challenge,
		AppID:     firstChallenge.AppID,
	})
	require.NoError(t, err, "failed to get first device registration response")

	firstDev, err := u2f.RegisterVerify(ctx, u2f.RegisterVerifyParams{
		DevName: firstDeviceName,
		Resp: u2f.RegisterChallengeResponse{
			RegistrationData: firstRegResp.RegistrationData,
			ClientData:       firstRegResp.ClientData,
		},
		StorageKey: username,
		Storage:    u2fStorage,
	})
	require.NoError(t, err, "failed to verify first device registration")
	require.NotNil(t, firstDev)

	// Register the second U2F device
	secondDeviceName := "u2f-key-2"
	secondMockDevice, err := mocku2f.Create()
	require.NoError(t, err, "failed to create second mock U2F device")

	// Initiate registration for the second device
	secondChallenge, err := u2f.RegisterInit(ctx, u2f.RegisterInitParams{
		StorageKey: username,
		AppConfig:  *u2fConfig,
		Storage:    u2fStorage,
	})
	require.NoError(t, err, "failed to initiate second device registration")

	secondRegResp, err := secondMockDevice.RegisterResponse(&u2f.RegisterChallenge{
		Challenge: secondChallenge.Challenge,
		AppID:     secondChallenge.AppID,
	})
	require.NoError(t, err, "failed to get second device registration response")

	secondDev, err := u2f.RegisterVerify(ctx, u2f.RegisterVerifyParams{
		DevName: secondDeviceName,
		Resp: u2f.RegisterChallengeResponse{
			RegistrationData: secondRegResp.RegistrationData,
			ClientData:       secondRegResp.ClientData,
		},
		StorageKey: username,
		Storage:    u2fStorage,
	})
	require.NoError(t, err, "failed to verify second device registration")
	require.NotNil(t, secondDev)

	// Verify both devices are registered in the system
	devices, err := as.AuthServer.GetMFADevices(ctx, username)
	require.NoError(t, err, "failed to get MFA devices")
	require.Len(t, devices, 2, "expected exactly 2 registered U2F devices")

	// Test 1: Check that U2FSignRequest includes challenges for both devices
	t.Run("U2FSignRequest with multiple devices", func(t *testing.T) {
		// Create auth server with password set
		err = as.AuthServer.CheckPasswordWOToken(username, []byte("password"))
		if err != nil {
			// Password is not yet set, so skip this part or continue with the test anyway
		}

		// Set password for the user
		err = as.AuthServer.UpsertPassword(username, []byte("password"))
		require.NoError(t, err, "failed to set user password")

		// Get U2F sign request (old API)
		u2fSignReq, err := as.AuthServer.U2FSignRequest(username, []byte("password"))
		require.NoError(t, err, "failed to get U2F sign request")
		require.NotNil(t, u2fSignReq)

		// REGRESSION: This test should show that only one challenge is present
		// when multiple devices are registered. The bug is that Challenges
		// should contain challenges for BOTH devices, but currently only
		// contains one.
		require.Len(t, u2fSignReq.Challenges, 2,
			"BUG: U2FSignRequest should include authentication challenges for all %d registered U2F devices, "+
				"but only %d challenge(s) were generated. "+
				"This causes users with multiple U2F tokens to be unable to use all their registered devices for authentication.",
			len(devices), len(u2fSignReq.Challenges))
	})

	// Test 2: Check that mfaAuthChallenge includes challenges for both devices
	t.Run("mfaAuthChallenge with multiple U2F devices", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		// Get MFA auth challenge
		mfaChallenge, err := as.AuthServer.(*auth.Server).GetMFAAuthenticateChallenge(ctx, username, u2fAuthStorage)
		require.NoError(t, err, "failed to get MFA authenticate challenge")
		require.NotNil(t, mfaChallenge)

		// REGRESSION: This test demonstrates that when creating an MFA
		// authentication challenge, the server should include a challenge for
		// each registered U2F device. If only one challenge is present instead
		// of two, it indicates the bug where multiple devices are not properly
		// supported.
		require.Len(t, mfaChallenge.U2F, 2,
			"BUG: mfaAuthChallenge should create authentication challenges for all %d registered U2F devices, "+
				"but only %d challenge(s) were created. "+
				"When a user has multiple U2F tokens registered, the server must generate a challenge for each device "+
				"so the user can choose which device to authenticate with.",
			len(devices), len(mfaChallenge.U2F))

		// Verify each challenge has unique key handles and challenges
		keyHandles := make(map[string]bool)
		for i, ch := range mfaChallenge.U2F {
			require.NotEmpty(t, ch.KeyHandle, "challenge %d missing KeyHandle", i)
			require.NotEmpty(t, ch.Challenge, "challenge %d missing Challenge", i)
			require.NotEmpty(t, ch.AppID, "challenge %d missing AppID", i)

			if keyHandles[ch.KeyHandle] {
				t.Errorf("duplicate key handle in challenges: %s", ch.KeyHandle)
			}
			keyHandles[ch.KeyHandle] = true
		}
	})

	// Test 3: Verify client/server version compatibility
	t.Run("U2F challenge format compatibility", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		// Get MFA auth challenge
		mfaChallenge, err := as.AuthServer.(*auth.Server).GetMFAAuthenticateChallenge(ctx, username, u2fAuthStorage)
		require.NoError(t, err, "failed to get MFA authenticate challenge")

		// The U2FAuthenticateChallenge struct should have both old and new format
		// for backward compatibility. The old format (single AuthenticateChallenge)
		// should be set to the first device's challenge.
		if len(mfaChallenge.U2F) > 0 {
			// For backward compatibility with older clients, the embedded
			// AuthenticateChallenge should match the first device's challenge
			require.NotNil(t, mfaChallenge.AuthenticateChallenge,
				"BUG: For backward compatibility with pre-6.0 clients, "+
					"the embedded AuthenticateChallenge field must be set when U2F challenges are present")
		}
	})

	// Test 4: Verify challenge storage uses device IDs correctly
	t.Run("challenge storage with device IDs", func(t *testing.T) {
		u2fAuthStorage, err := u2f.InMemoryAuthenticationStorage(as.AuthServer.Identity)
		require.NoError(t, err, "failed to create U2F authentication storage")

		// Get challenges for both devices
		mfaChallenge, err := as.AuthServer.(*auth.Server).GetMFAAuthenticateChallenge(ctx, username, u2fAuthStorage)
		require.NoError(t, err, "failed to get MFA authenticate challenge")

		// Each challenge should be retrievable using the device ID
		require.Len(t, mfaChallenge.U2F, 2, "expected 2 U2F challenges")

		// Verify that challenges were stored with correct device IDs
		for i, dev := range devices {
			u2fDev := dev.GetU2F()
			require.NotNil(t, u2fDev, "device %d is not a U2F device", i)

			// Try to retrieve the challenge for this device
			// This will fail if the challenge storage didn't properly store
			// challenges with device IDs
			challenge, err := u2fAuthStorage.GetU2FSignChallenge(username, dev.Id)
			require.NoError(t, err,
				"BUG: Failed to retrieve stored challenge for device %q. "+
					"Challenges must be stored with device IDs to support multiple devices.",
				dev.Id)
			require.NotNil(t, challenge, "stored challenge for device %q is nil", dev.Id)
		}
	})
}

// GetMFAAuthenticateChallenge is a helper method for accessing the mfaAuthChallenge
// internal method on the auth.Server.
func (as *auth.Server) GetMFAAuthenticateChallenge(ctx context.Context, user string, u2fStorage u2f.AuthenticationStorage) (*proto.MFAAuthenticateChallenge, error) {
	return as.(*auth.Server).(*auth.Server).mfaAuthChallenge(ctx, user, u2fStorage)
}

